using System.ComponentModel;
using System.Drawing.Design;
using System.Windows.Forms;
using System.Windows.Forms.Design;

public class MyTypeEditor : UITypeEditor
{
    public override object EditValue(ITypeDescriptorContext context,
        IServiceProvider provider, object value)
    {
        var editorService = provider?.GetService(typeof(IWindowsFormsEditorService))
            as IWindowsFormsEditorService;
        if (editorService == null)
            return value;

        var control = CreateEditorControl(value);

        // .NET 9 throws ArgumentNullException when null is passed to DropDownControl.
        // Guard against null before calling.
        if (control != null)
        {
            editorService.DropDownControl(control);
            value = GetValueFromControl(control);
        }

        return value;
    }

    private Control CreateEditorControl(object currentValue)
    {
        var listBox = new ListBox();
        listBox.Items.AddRange(new object[] { "Option A", "Option B", "Option C" });
        if (currentValue != null)
            listBox.SelectedItem = currentValue;
        return listBox;
    }

    private object GetValueFromControl(Control control)
    {
        return (control as ListBox)?.SelectedItem;
    }

    public override UITypeEditorEditStyle GetEditStyle(ITypeDescriptorContext context)
    {
        return UITypeEditorEditStyle.DropDown;
    }
}

